import { useState } from "react";
import API from "../services/api";
import { supabase } from '../services/supabaseClient';

function Upload() {
  const [file, setFile] = useState(null);
  const [text, setText] = useState("");
  const [summary, setSummary] = useState("");
  const [showSummary, setShowSummary] = useState(false);
  const [loading, setLoading] = useState(false);

  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");
  const [asking, setAsking] = useState(false);

  const [docId, setDocId] = useState(null);
  const [userId, setUserId] = useState(null);

  // Recommendation state (now handles a list of titles)
  const [papers, setPapers] = useState([]);
  const [loadingRec, setLoadingRec] = useState(false);

  // 📄 Helper to get current session token
  const getAuthHeader = async () => {
    const { data: { session } } = await supabase.auth.getSession();
    return session ? { Authorization: `Bearer ${session.access_token}` } : {};
  };

  // 📄 Upload
  const handleUpload = async () => {
    if (!file) return alert("Please select a file");

    try {
      setLoading(true);
      const authHeader = await getAuthHeader();

      const formData = new FormData();
      formData.append("file", file);

      // Sending token to backend to verify user and get Gmail
      const res = await API.post("/upload", formData, {
        headers: { 
          ...authHeader,
          "Content-Type": "multipart/form-data" 
        }
      });

      setText(res.data.preview);
      setDocId(res.data.doc_id);
      setUserId(res.data.user_id);

      // reset states
      setAnswer("");
      setQuestion("");
      setSummary("");
      setShowSummary(false);
      setPapers([]);

    } catch (error) {
      console.error(error);
      alert("Upload failed ❌ Check if backend is running on port 8000");
    } finally {
      setLoading(false);
    }
  };

  // 💬 Ask Question
  const askQuestion = async () => {
    if (!question) return alert("Enter a question");
    if (!docId) return alert("Upload a document first");

    try {
      setAsking(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/ask", {
        question: question,
        doc_id: docId,
        user_id: userId
      }, { headers: authHeader });

      setAnswer(res.data.answer);

    } catch (error) {
      console.error(error);
      alert("Error fetching answer ❌");
    } finally {
      setAsking(false);
    }
  };

  // 🧠 Summary
  const handleGenerateSummary = async () => {
    if (!text) return alert("Upload file first");

    try {
      setLoading(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/summarize", { text }, { headers: authHeader });

      setSummary(res.data.summary);
      setShowSummary(true);

    } catch (error) {
      console.error(error);
      alert("Summary failed ❌");
    } finally {
      setLoading(false);
    }
  };

  // 🔍 Recommend Papers (Modified for OpenAlex & Titles Only)
  const handleRecommend = async () => {
    if (!text) return alert("Upload a paper first");

    try {
      setLoadingRec(true);
      const authHeader = await getAuthHeader();

      // We send 'query' to match the backend payload.get("query")
      const res = await API.post("/recommend", {
        query: text 
      }, { headers: authHeader });

      // Backend now returns { "recommendations": ["Title 1", "Title 2", "Title 3"] }
      setPapers(res.data.recommendations || []);

    } catch (error) {
      console.error(error);
      alert("Failed to fetch recommendations ❌");
    } finally {
      setLoadingRec(false);
    }
  };

  return (
    <div style={{ marginTop: "20px", maxWidth: "800px", margin: "auto", padding: "20px" }}>
      <h3>Upload Research Paper</h3>

      <input
        type="file"
        accept=".pdf"
        onChange={(e) => setFile(e.target.files[0])}
      />

      <br /><br />

      <button onClick={handleUpload} disabled={loading}>
        {loading ? "Processing..." : "Upload & Analyze"}
      </button>

      {/* 📄 Preview */}
      {text && (
        <div style={{
          marginTop: "20px",
          padding: "15px",
          border: "1px solid #ccc",
          borderRadius: "10px",
          maxHeight: "200px",
          overflowY: "scroll",
        }}>
          <h4>Extracted Text (Preview)</h4>
          <p>{text.slice(0, 1000)}...</p>
        </div>
      )}

      {/* 🔘 FEATURE BUTTONS */}
      {text && (
        <div style={{ marginTop: "15px" }}>
          <button onClick={handleGenerateSummary} style={{ marginRight: "10px" }}>
            🧠 Summarize
          </button>

          <button onClick={handleRecommend} disabled={loadingRec}>
            {loadingRec ? "Finding..." : "🔍 Recommend Top 3"}
          </button>
        </div>
      )}

      {/* 🧠 Summary Result */}
      {showSummary && summary && (
        <div style={{ marginTop: "20px", backgroundColor: "#f0f7ff", padding: "15px", borderRadius: "10px" }}>
          <h3>Summary</h3>
          <p>{summary}</p>
        </div>
      )}

      {/* 💬 Q&A Section */}
      {text && (
        <div style={{ marginTop: "20px" }}>
          <h3>💬 Ask Questions</h3>
          <input
            type="text"
            value={question}
            onChange={(e) => setQuestion(e.target.value)}
            placeholder="Ask something..."
            style={{ width: "80%", padding: "8px" }}
          />
          <button onClick={askQuestion} style={{ marginLeft: "10px", padding: "8px" }}>
            {asking ? "Thinking..." : "Ask"}
          </button>

          {answer && (
            <div style={{ marginTop: "15px", padding: "10px", borderLeft: "4px solid #007bff" }}>
              <h4>Answer:</h4>
              <p>{answer}</p>
            </div>
          )}
        </div>
      )}

      {/* 📚 Recommendations Result */}
      {papers.length > 0 && (
        <div style={{
          marginTop: "20px",
          padding: "15px",
          border: "1px solid #28a745",
          borderRadius: "10px",
          backgroundColor: "#f4fff4"
        }}>
          <h3 style={{ color: "#28a745" }}>📚 Top 3 Suitable Papers</h3>
          <ul style={{ listStyleType: "none", padding: 0 }}>
            {papers.map((title, i) => (
              <li key={i} style={{
                padding: "10px 0",
                borderBottom: i < 2 ? "1px solid #eee" : "none",
                fontWeight: "bold"
              }}>
                • {title}
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

export default Upload;
